SELECT SUM(quantity) AS total_quantity
FROM item_sizes
WHERE item_id = 1;

SELECT DISTINCT size_id
FROM sizes
ORDER BY size_id ASC;

SELECT quantity
FROM item_sizes
WHERE item_id = 1 AND size_id = 1;

SELECT quantity AS total_quantity
FROM item_sizes
WHERE item_size_id = 1;

SELECT size_id, SUM(quantity) AS total_quantity
FROM item_sizes
GROUP BY size_id;
